def calculate_benefits_disbursement(client_data, stability_score):
    """
    Calculate adaptive benefits distribution based on stability metrics
    """
    base_benefit = client_data['monthly_benefit_amount']

    # Determine restriction tier
    if stability_score >= 70:
        cash_percentage = 1.0
        credits_percentage = 0.0
        tier = "Full Autonomy"
    elif stability_score >= 50:
        cash_percentage = 0.7
        credits_percentage = 0.3
        tier = "Guided Support"
    elif stability_score >= 30:
        cash_percentage = 0.4
        credits_percentage = 0.6
